code.example:
function ContentCardGrid({ items }) {
  const { div, span, h3, img } = tags;

  return div({ class: css('_grid _gc3 _gap6 _p4') },
    ...items.map(item =>
      Card({},
        img({ src: item.image, alt: item.title, class: css('_wfull _h[200px] _object[cover]') }),
        Card.Body({ class: css('_flex _col _gap2') },
          h3({ class: css('_heading5') }, item.title),
          span({ class: css('_caption _fgmuted _lineClamp2') }, item.description),
          div({ class: css('_flex _aic _gap3 _fgmuted _textsm') },
            span({}, icon('clock'), ` ${item.time} min`),
            span({}, icon('users'), ` ${item.servings} servings`)
          ),
          div({ class: css('_flex _gap1 _flexWrap') },
            ...(item.tags || []).map(t => Chip({ size: 'sm' }, t))
          ),
          div({ class: css('_flex _aic _jcsb _mt2') },
            div({ class: css('_flex _aic _gap2') },
              Avatar({ src: item.author?.avatar, size: 'xs' }),
              span({ class: css('_textsm') }, item.author?.name)
            ),
            span({ class: css('_textsm _fgmuted') }, icon('git-fork'), ` ${item.forks || 0}`)
          )
        )
      )
    )
  );
}

