code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Card, Chip, icon } from 'decantr/components';

code.example:
function ResourceGrid({ apps }) {
  const { div, span, h4 } = tags;
  const statusVariant = s => s === 'deployed' ? 'success' : s === 'pending' ? 'warning' : 'error';

  return div({ class: css('_grid _gcaf280 _gap4') },
    ...apps.map(app =>
      Card({ hover: true },
        Card.Body({ class: css('_flex _col _gap3 _p4') },
          div({ class: css('_flex _aic _jcsb') },
            div({ class: css('_flex _aic _gap2') },
              icon('box', { size: '1em', class: css('_fgprimary') }),
              h4({ class: css('_textsm _bold') }, app.name)
            ),
            Badge({ variant: statusVariant(app.status), size: 'sm' }, app.status)
          ),
          div({ class: css('_flex _gap2 _flexWrap') },
            Chip({ label: `${app.cpu} CPU`, size: 'xs', icon: 'cpu' }),
            Chip({ label: `${app.memory} MB`, size: 'xs', icon: 'hard-drive' }),
            Chip({ label: `${app.machines} machines`, size: 'xs', icon: 'server' }),
            Chip({ label: app.region, size: 'xs', icon: 'globe' })
          )
        )
      )
    )
  );
}

