import { Badge, Button, Card, icon } from 'decantr/components';

code.example:
function ServiceGrid({ services }) {
  const { div, span, h4, p } = tags;
  const dotClass = s => s === 'connected' ? '_bgsuccess' : s === 'beta' ? '_bgwarning' : '_bgmuted';
  const actionLabel = s => s === 'connected' ? 'Manage' : s === 'beta' ? 'Try Now' : 'Connect';

  return div({ class: css('_grid _gcaf280 _gap4') },
    ...services.map(svc =>
      Card({ hover: true },
        Card.Body({ class: css('_flex _col _aic _gap3 _p4 _tc') },
          div({ class: css('_w12 _h12 _rfull _bgprimary/10 _flex _center') },
            icon(svc.icon, { size: '1.5em', class: css('_fgprimary') })
          ),
          div({ class: css('_flex _col _aic _gap1') },
            div({ class: css('_flex _aic _gap2') },
              h4({ class: css('_textsm _bold') }, svc.name),
              div({ class: css(`_w[8px] _h[8px] _rfull ${dotClass(svc.status)}`) })
            ),
            p({ class: css('_textxs _fgmuted _tc') }, svc.description)
          ),
          Button({ variant: 'outline', size: 'sm' }, actionLabel(svc.status))
        )
      )
    )
  );
}

