code.example:
function UserGrid({ users }) {
  const { div, span, h4 } = tags;

  return div({ class: css('_grid _gcaf280 _gap4') },
    ...users.map(user =>
      Card({ hover: true },
        Card.Body({ class: css('_flex _col _aic _gap3 _p4 _tc') },
          Avatar({ name: user.name, size: 'lg' }),
          div({ class: css('_flex _col _aic _gap1') },
            h4({ class: css('_textsm _bold') }, user.name),
            Badge({ variant: 'outline', size: 'sm' }, user.role),
            Chip({ label: user.status, size: 'xs', variant: user.status === 'active' ? 'success' : 'default' })
          ),
          div({ class: css('_flex _gap2') },
            Button({ variant: 'ghost', size: 'sm' }, icon('mail', { size: '1em' })),
            Button({ variant: 'ghost', size: 'sm' }, icon('message-circle', { size: '1em' })),
            Button({ variant: 'ghost', size: 'sm' }, icon('user', { size: '1em' }))
          )
        )
      )
    )
  );
}

